var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 건국기념전당, 타나베린\\n레아 슈나이더","JPN":"グロニア建国記念館、タナベリン\\nレア・シュナイダー","ENG":"Gronia’s National Foundation Hall, Tanaberin\\nLeah Schneider","TWN":"格羅尼亞 建國紀念堂，達那貝林\\n蕾亞·修奈德","THA":"หอสถาปนาแห่งชาติของโกรเนีย\\nเลอาห์ ชไนเดอร์","VTN":"Hội trường Thành lập Quốc gia Gronia, Tanaberin\\nLeah Schneider","SCN":"格洛尼亚建国纪念堂，特纳贝林\\n蕾娅·施耐德","DEU":"Gronias Palast der Gründung, Tanaberin\\nLeah Schneider","FRA":"[["},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"후우……. 오늘 청소할 구역은 이걸로 끝인가?","JPN":"ふう……今日掃除するエリアはこれで終わりかな？","ENG":"Whew... Is today’s cleanup finally over?","TWN":"呼……今天要打掃的地方應該就這些吧？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"건국절까지 끝내려면 지금 인원들만 가지곤 어림도 없겠는데.","JPN":"この人数で建国記念日まで終わらせるのは無理だよ。","ENG":"If we want to finish by National Foundation Day, it’ll be difficult with these few people.","TWN":"要在國慶之前處理完畢的話，光靠目前的人力應該有困難吧？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"하하. 걱정 마요, 레아.","JPN":"はは。心配する必要はないですよ、レア。","ENG":"Ha ha. Don’t worry, Leah.","TWN":"哈哈，你儘管放心，蕾亞。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"건물이 크긴 하지만 관리가 필요한 곳은 절반도 안 돼요. 사용하지 않는 구역이 많거든요.","JPN":"建物は大きいですが、管理が必要な場所は半分もありません。使っていないエリアが多いですから。","ENG":"Although the building is large, only half of it requires maintenance. Many areas are unused.","TWN":"這棟建築物雖然很大，但需要管理的地方不多，因為有很多區域都沒在使用。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"특히 대정화전쟁 시기에 증축한 곳들은 미로나 다름없어요. 지하실에서 실종된 사람 이야기는 유명하잖아요?","JPN":"特に大浄化戦争の時期に増築した部分は迷路同然です。地下室で失踪した人の話は有名でしょう？","ENG":"In particular, areas built during the Grand Purification War are like a maze. The story of a man going missing in the basement is quite famous, right?","TWN":"尤其是在大淨化戰爭時期擴建的地方，根本就像迷宮一樣，那個地下室失蹤奇案不是很有名嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"이런, 불평하는 걸 들켜 버렸네요. 실장님.","JPN":"おっと、愚痴がバレてしまいましたね。室長。","ENG":"Oh, I’m sorry if I’ve been complaining a little too much, Manager.","TWN":"哎呀，被室長發現，我其實是在抱怨呢～"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"괜찮아요. 담당 구역이 다 끝났으면 이만 가 보셔도 됩니다.","JPN":"大丈夫です。担当エリアが終わったのなら帰っても構いません。","ENG":"No problem. You may go now if your area is all finished.","TWN":"沒事的，你負責的區域處理完畢後，就可以先離開沒問題。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"근무 시간이 아직 남았는데, 그래도 될까요?","JPN":"まだ勤務時間が残ってますが、大丈夫ですか？","ENG":"It’s a bit earlier than when I normally get off, is it really okay?","TWN":"但現在還是上班時間，這樣沒關係嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"그럼요. 어차피 몇 분 있으면 공연 연습 때문에 드나들기도 힘들 겁니다.","JPN":"ええ。どうせ数分後には公演の練習があるので、出入りしづらくなるでしょう。","ENG":"Of course. In a few more minutes, it will be difficult to get in and out due to the rehearsal.","TWN":"當然沒關係，反正再過幾分鐘後，就要開始彩排演出，到時候進出會很不方便。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"여기 오늘치 일당이에요. 조금 넉넉하게 챙겨 드렸습니다.","JPN":"さあ、今日の日給です。少し多めに入れておきました。","ENG":"Here are your wages for the day. This should be more than enough.","TWN":"這是今天的工資，我有多給你一點。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"아. 그러고 보니 친구 분이 어머님을 모시고 오셨더군요.","JPN":"あ。そういえばお友達がお母さんと一緒にいらしてましたよ。","ENG":"Ah. Come to think of it, a friend of yours brought your mother.","TWN":"話說回來，你的朋友好像帶著媽媽來找你。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"안젤라가요?","JPN":"アンジェラがですか？","ENG":"You mean Angela?","TWN":"你說安潔拉嗎？"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAD_GRONIA_NULL_NULL","text":{"KOREA":"네. 관심 있으면 2층 좌석에서 좀 구경하다 가세요. 출입구를 열어 둘 테니까요.","JPN":"はい。気になるなら、2階の席でちょっと見ていきなさい。出入口を開けておきますから。","ENG":"Correct. If you’re interested, take the seats on the second floor, I’ll leave the door open.","TWN":"對，有興趣的話，你們可以上2樓的觀眾席參觀一下再走，出口我會幫你開著。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"HEAD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NAME","text":{"KOREA":"배려는 감사하지만 괜찮아요. 먼저 퇴근하겠습니다, 실장님.","JPN":"お気遣いはありがたいですが、大丈夫です。お先に失礼します、室長。","ENG":"Thank you for thinking of me, but I’m okay. I’ll be going home, Manager.","TWN":"謝謝室長費心，但沒關係，我先下班了。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니, 춥지는 않으세요?","JPN":"おばさん、寒くないですか？","ENG":"Madam, aren’t you cold?","TWN":"伯母，你會冷嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};